#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

int main() {
  int T;
  scanf("%d", &T);
  while(T--){
    int N, Q;
    scanf("%d %d", &N, &Q);
    int* cards = (int*)malloc(N * sizeof(int));
    for(int i = 0; i < N; i++){
      scanf("%d", &cards[i]);
    }
    for(int i = 0; i < Q; i++){
      int M;
      scanf("%d", &M);
      int count = 0;
      for(int mask = 0; mask < (1 << N); mask++){
        int sum = 0;
        for(int j = 0; j < N; j++){
          if((mask & (1 << j)) != 0){
            sum += cards[j];
          }
        }
        if(abs(sum) % M == 0){
          count++;
        }
      }
      printf("%d\n", count);
    }
    free(cards);
  }
  return 0;
}

