    Scanner scanner = new Scanner(System.in);
    int T = scanner.nextInt();
    while(T-- > 0){
      int N = scanner.nextInt();
      int Q = scanner.nextInt();
      int[] cards = new int[N];
      for(int i = 0; i < N; i++){
        cards[i] = scanner.nextInt();
      }
      for(int i = 0; i < Q; i++){
        int M = scanner.nextInt();
        int count = 0;
        for(int mask = 0; mask < (1 << N); mask++){
          int sum = 0;
          for(int j = 0; j < N; j++){
            if((mask & (1 << j)) != 0){
              sum += cards[j];
            }
          }
          if(Math.abs(sum) % M == 0){
            count++;
          }
        }
        System.out.println(count);
      }
